import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import AiAssistant from './components/AiAssistant';
// Import all your page components
import AuthorityPage from './pages/Authority';
import BinPage from './pages/Bin';
import DriverPage from './pages/Driver';
import UserPage from './pages/User';
import VehiclePage from './pages/Vehicle';

function App() {
      const appStyles = {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
        backgroundImage: 'radial-gradient(at 0% 0%, rgba(17, 153, 142, 0.3) 0px, transparent 50%), radial-gradient(at 100% 100%, rgba(56, 239, 125, 0.3) 0px, transparent 50%)',
        fontFamily: "'Inter', '-apple-system', 'BlinkMacSystemFont', 'Segoe UI', 'Roboto', 'Oxygen', 'Ubuntu', 'Cantarell', 'Fira Sans', 'Droid Sans', 'Helvetica Neue', sans-serif",
        paddingBottom: '40px',
        position: 'relative',
      };

  const containerStyles = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '30px',
    minHeight: 'calc(100vh - 80px)',
  };

      const welcomeStyles = {
        textAlign: 'center',
        color: '#333',
        fontSize: '2.5rem',
        fontWeight: '700',
        marginTop: '40px',
        background: 'rgba(255, 255, 255, 0.95)',
        backdropFilter: 'blur(10px)',
        padding: '50px',
        borderRadius: '24px',
        border: 'none',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3), 0 10px 30px rgba(0,0,0,0.2)',
        animation: 'fadeIn 0.6s ease-in',
      };

  return (
    <div style={appStyles}>
      <Router>
        <Navbar />
        <div style={containerStyles}>
          <Routes>
            {/* Default landing page */}
                <Route path="/" element={
                  <div style={welcomeStyles}>
                    <div style={{ fontSize: '4rem', marginBottom: '15px' }}>♻️</div>
                    <h1 style={{ 
                      background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
                      WebkitBackgroundClip: 'text',
                      WebkitTextFillColor: 'transparent',
                      backgroundClip: 'text'
                    }}>Smart Waste Management System</h1>
                    <p style={{ fontSize: '1.1rem', marginTop: '20px', color: '#11998e', fontWeight: '500' }}>
                      🌱 Efficient & Eco-Friendly Waste Collection Operations
                    </p>
                    <style>{`
                      @keyframes fadeIn {
                        from { opacity: 0; transform: translateY(20px); }
                        to { opacity: 1; transform: translateY(0); }
                      }
                      @keyframes float {
                        0%, 100% { transform: translateY(0px); }
                        50% { transform: translateY(-10px); }
                      }
                      .feature-card {
                        animation: fadeIn 0.6s ease-in, float 3s ease-in-out infinite;
                        animation-fill-mode: both;
                      }
                      .feature-card:nth-child(1) { animation-delay: 0s, 0s; }
                      .feature-card:nth-child(2) { animation-delay: 0.1s, 0.5s; }
                      .feature-card:nth-child(3) { animation-delay: 0.2s, 1s; }
                      .feature-card:nth-child(4) { animation-delay: 0.3s, 1.5s; }
                      .feature-card:nth-child(5) { animation-delay: 0.4s, 2s; }
                      .feature-card:hover {
                        transform: translateY(-8px) scale(1.02);
                        box-shadow: 0 25px 50px rgba(0,0,0,0.25) !important;
                      }
                    `}</style>
                    <div style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                      gap: '30px',
                      marginTop: '40px'
                    }}>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(17, 153, 142, 0.4)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>🏛️</div>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>Authority</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Manage waste management authorities and environmental regulations</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #56ab2f 0%, #a8e063 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(86, 171, 47, 0.4)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>🚛</div>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>Driver</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Manage eco-friendly collection drivers and routes</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #2980b9 0%, #3498db 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(41, 128, 185, 0.4)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>🚜</div>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>Vehicle</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Track eco-friendly waste collection fleet and routes</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #f39c12 0%, #f1c40f 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(243, 156, 18, 0.4)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>🗑️</div>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>Smart Bin</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Monitor smart bins, fill levels, and collection schedules</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #27ae60 0%, #2ecc71 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(46, 204, 113, 0.4)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>👥</div>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>User</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Manage system users, waste contributors, and access</p>
                      </div>
                    </div>
                  </div>
                } />

            {/* Routes for each entity management page */}
            <Route path="/authority" element={<AuthorityPage />} />
            <Route path="/bin" element={<BinPage />} />
            <Route path="/driver" element={<DriverPage />} />
            <Route path="/user" element={<UserPage />} />
            <Route path="/vehicle" element={<VehiclePage />} />
          </Routes>
        </div>
        <AiAssistant />
      </Router>
    </div>
  );
}

export default App;
